parameters.jsCode:
// Extract text from the active branch (Agent or Quick Reply)
const json = $input.first().json;
let text = '';

// Try to get text from input first
if (json.output) {
    text = json.output; // From Sales Agent
} else if (json.quick_reply) {
    text = json.quick_reply; // From Quick Reply
} else {
    // Fallback: try to resolve from node references safely
    try { text = $('🤖 Sales Agent').first().json.output; } catch(e) {}
    if (!text) try { text = $('💬 Respuesta Rápida').first().json.quick_reply; } catch(e) {}
}

text = text || '';

// Extract [FOTO:apartment_id] tags
const photoMatches = text.match(/\[FOTO:(\w+)\]/gi) || [];
const photo_apartments = photoMatches.map(m => m.match(/FOTO:(\w+)/i)[1]);

// Clean text: remove tags
const clean_text = text.replace(/\[FOTO:\w+\]/gi, '').replace(/\[VIDEO:\w+\]/gi, '').trim();

// Get context from Router (always available)
const router = $('🧭 Router Inteligente').first().json;

return [{
    json: {
        clean_text,
        has_photos: photo_apartments.length > 0,
        photo_apartments,
        account_id: router.account_id,
        conversation_id: router.conversation_id,
        sender_name: router.sender_name
    }
}];

// Build photo fetch items from apartment IDs
const apts = $('🖼️ Procesar Fotos').item.json.photo_apartments;
const account_id = $('🖼️ Procesar Fotos').item.json.account_id;
const conversation_id = $('🖼️ Procesar Fotos').item.json.conversation_id;

const items = apts.map(apt => ({
    json: {
        apt_id: apt,
        api_url: "https://availability-api.parallext.cloud/apartments/" + apt + "/photos",
        account_id: account_id,
        conversation_id: conversation_id
    }
}));
return items;

// 🧭 Router Inteligente - bypasses LLM for trivial messages
const msg = $('📋 Extraer Datos').item.json.message_content.trim();
const name = $('📋 Extraer Datos').item.json.sender_name;
const lower = msg.toLowerCase().replace(/[!¡¿?.,;:]/g, '').trim();

// Only match if the ENTIRE message is a greeting or ack (no compound messages)
const GREETINGS = /^(hola|hi|hello|hey|buenas?|buenos?\s*(dias|tardes|noches)|que\s*tal|saludos?)$/i;
const ACKS = /^(ok|okay|listo|vale|perfecto|genial|gracias|muchas\s*gracias|de\s*acuerdo|entendido|claro|super|excelente|buenisimo|chevere)$/i;

let useAgent = true;
let quickReply = '';

if (GREETINGS.test(lower)) {
    // Validar nombre: que exista, no sea solo números, y solo contenga letras/espacios (sin emojis/puntos/etc)
    const isValidName = name && name.trim() && !/^\+?\d+$/.test(name.trim()) && /^[a-zA-ZáéíóúÁÉÍÓÚñÑ \-]+$/.test(name.trim());

    quickReply = isValidName 
        ? `¡Hola, ${name.trim()}! 👋 Soy Sofía de Amazon Minimalist. ¿En qué puedo ayudarte? 😊`
        : `¡Hola! Soy Sofía de Amazon Minimalist. ¿Con quién tengo el gusto? 😊`;

    useAgent = false;
} else if (ACKS.test(lower)) {
    quickReply = '¡Con gusto! Si necesitas algo más, aquí estoy 😊';
    useAgent = false;
}

return [{
    json: {
        useAgent,
        quickReply,
        message_content: msg,
        account_id: $('📋 Extraer Datos').item.json.account_id,
        conversation_id: $('📋 Extraer Datos').item.json.conversation_id,
        sender_name: name,
        sender_phone: $('📋 Extraer Datos').item.json.sender_phone,
        sender_email: $('📋 Extraer Datos').item.json.sender_email
    }
}];

// Expand photo URLs into individual items (send up to 8)
const response = $input.first().json;
const photos = response.photos || [];

const account_id = $('🖼️ Procesar Fotos').item.json.account_id;
const conversation_id = $('🖼️ Procesar Fotos').item.json.conversation_id;

// Send up to 8 photos
const selected = photos.slice(0, 8);

return selected.map(url => ({
    json: {
        photo_url: url,
        account_id: account_id,
        conversation_id: conversation_id
    }
}));

